final:
module top_module(number, obf_data);input [3:0] number;
output reg [7:0] obf_data;

always @ (number) begin
	case(number)
		4'b0000: obf_data = 8'h30;
		4'b0001: obf_data = 8'h31;
		4'b0010: obf_data = 8'h32;
		4'b0011: obf_data = 8'h33;
		4'b0100: obf_data = 8'h34;
		4'b0101: obf_data = 8'h35;
		4'b0110: obf_data = 8'h36;
		4'b0111: obf_data = 8'h37;
		4'b1000: obf_data = 8'h38;
		4'b1001: obf_data = 8'h39;
		default: obf_data = 8'h20;
	endcase
end

endmodule
